<span class="line"><span style="color:#89B4FA;font-style:italic;">        collect_observations</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">response</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">tool_calls</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">results</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#CDD6F4;"> state</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">history</span><span style="color:#9399B2;">);</span></span>
